import{_ as s,C as t,o as n,c as l,j as o,a as d,E as r,w as c,am as h}from"./chunks/framework.Ck27G9m2.js";const y=JSON.parse('{"title":"Firmware Update (DFU)","description":"","frontmatter":{},"headers":[],"relativePath":"examples/dfu.md","filePath":"examples/dfu.md"}'),p={name:"examples/dfu.md"};function u(f,e,m,w,g,b){const a=t("DfuDemo"),i=t("ClientOnly");return n(),l("div",null,[e[0]||(e[0]=o("h1",{id:"firmware-update-dfu",tabindex:"-1"},[d("Firmware Update (DFU) "),o("a",{class:"header-anchor",href:"#firmware-update-dfu","aria-label":'Permalink to "Firmware Update (DFU)"'},"​")],-1)),r(i,null,{default:c(()=>[r(a)]),_:1}),e[1]||(e[1]=h('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Device Firmware Update (DFU) is the process of updating the internal software running on your Boks device. This tool allows you to perform this update directly from your browser using Web Bluetooth.</p><p>The update process consists of two main steps:</p><h3 id="step-1-preparation-switching-to-dfu-mode" tabindex="-1">Step 1: Preparation (Switching to DFU Mode) <a class="header-anchor" href="#step-1-preparation-switching-to-dfu-mode" aria-label="Permalink to &quot;Step 1: Preparation (Switching to DFU Mode)&quot;">​</a></h3><p>In its normal operating state, the Boks device does not accept firmware updates directly for security and stability reasons.</p><ol><li>First, connect to your Boks device using the global controller at the bottom of the screen.</li><li>The controller will verify your hardware version and battery level.</li><li>If the battery is healthy, click <strong>&quot;Switch to DFU mode&quot;</strong>.</li><li>The application will send a specific command (writing <code>0x01</code> to characteristic <code>8ec90001-f315-4f60-9fb8-838830daea50</code> of the DFU service <code>0000fe59-0000-1000-8000-00805f9b34fb</code>).</li><li>Your Boks will restart. It will now broadcast a different name: <code>DfuTarg</code> or <code>Boks_DFU</code>.</li></ol><h3 id="step-2-flashing-the-firmware" tabindex="-1">Step 2: Flashing the Firmware <a class="header-anchor" href="#step-2-flashing-the-firmware" aria-label="Permalink to &quot;Step 2: Flashing the Firmware&quot;">​</a></h3><p>Once your device is in DFU mode, the interface will automatically switch to the flashing panel.</p><ol><li>Select the firmware <code>.zip</code> file provided for your specific Boks hardware revision.</li><li>Click <strong>&quot;Start Flashing&quot;</strong>.</li><li>The browser will negotiate with the bootloader and begin transferring the firmware chunks.</li><li><strong>Do not close the tab or turn off your computer during this process.</strong></li></ol><p>Once the transfer reaches 100%, the Boks will validate the firmware and reboot automatically into the new operating system.</p><hr><h2 id="safety-troubleshooting" tabindex="-1">Safety &amp; Troubleshooting <a class="header-anchor" href="#safety-troubleshooting" aria-label="Permalink to &quot;Safety &amp; Troubleshooting&quot;">​</a></h2><p>Firmware updates involve rewriting the core memory of the device. While the Boks hardware is designed to be resilient, interruptions can cause the device to become temporarily unavailable.</p><h3 id="interrupted-updates" tabindex="-1">Interrupted Updates <a class="header-anchor" href="#interrupted-updates" aria-label="Permalink to &quot;Interrupted Updates&quot;">​</a></h3><p>If the update process is interrupted (e.g., your computer goes to sleep, the browser tab is closed, or the Bluetooth connection drops), the behavior depends on your hardware version:</p><ul><li><strong>Boks V3 (nRF52811):</strong> The device will be <strong>temporarily unavailable</strong> or &quot;stuck in update mode&quot; (<code>DfuTarg</code>). It will not respond to normal commands or the physical button. <strong>Do not panic.</strong> To restore it, simply reconnect to the <code>DfuTarg</code> device and successfully complete the flashing process from Step 2.</li><li><strong>Boks V4 (nRF52833):</strong> These devices handle interruptions more gracefully. Often, simply removing the batteries and reinserting them is enough to restore the device to its previous working state.</li></ul><h3 id="invalid-firmware-files" tabindex="-1">Invalid Firmware Files <a class="header-anchor" href="#invalid-firmware-files" aria-label="Permalink to &quot;Invalid Firmware Files&quot;">​</a></h3><p>The bootloader will refuse to flash a firmware file that is corrupted or intended for a different hardware version. If you see an error like:</p><blockquote><p>&quot;The firmware file is invalid or corrupted for this model.&quot;</p></blockquote><p>or</p><blockquote><p>&quot;This firmware is not compatible with your Boks hardware version.&quot;</p></blockquote><p>Please verify that you have downloaded the correct <code>.zip</code> file for your specific Boks model (e.g., V3 vs V4).</p>',22))])}const k=s(p,[["render",u]]);export{y as __pageData,k as default};
